Patch Set 2:

> I'm wondering if it might be better to make the change look more
 > like upstream.
 > 
 > The gist of the upstream API is that all the timer users stop using
 > the "unsigned long data" and use the from_timer() to get the object
 > containing the timer.
 > 
 > From a backport perspective I think from_timer() and timer_setup()
 > can be emulated in backports.
 > 
 > The only issue is the callback routine would need to be wrapped to
 > add the now unused "unsigned long" as the last arg when indicated.

I have confirmed my idea can work.

Here is the emulation:

#ifndef HAVE_TIMER_SETUP
#define cfs_timer_cb_arg_t unsigned long
#define timer_setup(t, cb, f) \
       setup_timer(t, cb, (unsigned long)t)
#define from_timer(var, t, fld) \
       container_of((struct timer_list *)t, typeof(*var), fld)
#else
#define cfs_timer_cb_arg_t struct timer_list *
#endif

I built this on RHEL 7.3 and 4.14.  (4.14 has the new API as well as the old API).

So the process would be:
- Change to use the new timer API
  * The lustre in 4.15 staging has some examples
  * Also see https://lwn.net/Articles/735892
  * upstream patches to convert to the new API
- Compile on 4.14 to test
- Use cfs_timer_cb_arg_t in the callbacks

In cases where the containing struct cannot be derived use a stub struct.

See kgnilnd_timer below:

diff --git a/lnet/klnds/gnilnd/gnilnd_conn.c b/lnet/klnds/gnilnd/gnilnd_conn.c
index a3f7c75..fcd1251 100644
--- a/lnet/klnds/gnilnd/gnilnd_conn.c
+++ b/lnet/klnds/gnilnd/gnilnd_conn.c
@@ -2434,11 +2434,15 @@ kgnilnd_repost_wc_dgrams(kgn_device_t *dev)
        RETURN(did_something);
 }

+struct kgnilnd_timer {
+       struct timer_list timer;
+       kgn_device_t *dev
+};
+
 static void
-kgnilnd_dgram_poke_with_stick(unsigned long arg)
+kgnilnd_dgram_poke_with_stick(cfs_timer_cb_arg_t t)
 {
-       int             dev_id = arg;
-       kgn_device_t    *dev = &kgnilnd_data.kgn_devices[dev_id];
+       kgn_device_t    *dev = from_timer(dev, t, timer);

        wake_up(&dev->gnd_dgram_waitq);
 }
@@ -2455,6 +2459,9 @@ kgnilnd_dgram_mover(void *arg)
        struct timer_list        timer;
        unsigned long            deadline = 0;
        DEFINE_WAIT(wait);
+       struct kgnilnd_timer timer = {
+               .dev = dev,
+       }

        snprintf(name, sizeof(name), "kgnilnd_dg_%02d", dev->gnd_id);
        cfs_block_allsigs();
@@ -2521,7 +2528,7 @@ kgnilnd_dgram_mover(void *arg)

                prepare_to_wait(&dev->gnd_dgram_waitq, &wait, TASK_INTERRUPTIBLE);

-               setup_timer(&timer, kgnilnd_dgram_poke_with_stick, dev->gnd_id);
+               timer_setup_on_stack(&timer.timer, kgnilnd_dgram_poke_with_stick, 0);
                mod_timer(&timer, (long) jiffies + timeout);

                /* last second chance for others to poke us */
@@ -2546,5 +2553,6 @@ kgnilnd_dgram_mover(void *arg)
        }

        kgnilnd_thread_fini();
+       destroy_timer_on_stack(&timer.timer);
        return 0;
 }

We will also need to have timer_setup_on_stack() emulation.

I couldn't build all the code paths, like gnilnd.

Mike
